// order-state.service.ts - VERSIONE SICURA
import { Injectable, inject } from '@angular/core';
import { SupabaseService } from '../Base/supabase.service';
import { AuthService } from '../Base/auth.service';

type Role = 'kitchen' | 'waiter';

interface Transitions {
  [key: string]: string[];
}

@Injectable({ providedIn: 'root' })
export class OrderStateService {
  private supabase = inject(SupabaseService).getSupabaseClient();
  private authService = inject(AuthService);

  // Transizioni per ruolo KITCHEN
  private kitchenTransitions: Transitions = {
    'ordered': ['waiting', 'out_of_stock'],
    'waiting': ['preparing', 'ready', 'out_of_stock'],
    'preparing': ['ready', 'out_of_stock'],
    'ready': ['out_of_stock'],
    'out_of_stock': []
  };

  // Transizioni per ruolo WAITER
  private waiterTransitions: Transitions = {
    'ordered': ['waiting', 'cancelled'],
    'waiting': ['preparing', 'cancelled'],
    'preparing': ['ready', 'cancelled'],
    'ready': ['served', 'cancelled'],
    'served': [],
    'cancelled': ['ordered']
  };

  canTransitionItem(currentStatus: string, targetStatus: string, role: Role): boolean {
    console.log(`🔍 Verifica transizione: ${currentStatus} → ${targetStatus} (${role})`);
    
    if (currentStatus === targetStatus) return false;
    if (targetStatus === 'out_of_stock') return true;
    
    const transitions = role === 'kitchen' ? this.kitchenTransitions : this.waiterTransitions;
    const allowed = transitions[currentStatus] || [];
    return allowed.includes(targetStatus);
  }

async updateItemStatus(itemId: string, status: string, comandaId?: string): Promise<boolean> {

  try {
    const restaurantId = await this.authService.getCurrentRestaurantId();
    if (!restaurantId) return false;

    const { error } = await this.supabase
      .from('order_items')
      .update({ status, updated_at: new Date().toISOString() })
      .eq('id', itemId);

    if (!error && comandaId) {
      await this.syncComandaStatus(comandaId); // <--- SINCRONIZZA VERSO L'ALTO
    }
    return !error;
  } catch (error) {
    return false;
  }
}

async updateComandaStatus(comandaId: string, status: string): Promise<boolean> {
  try {
    const restaurantId = await this.authService.getCurrentRestaurantId();
    if (!restaurantId) return false;

    console.log(`🔄 [OrderStateService] Aggiornamento comanda ${comandaId} a ${status}`);

    // 1. Aggiorna la comanda
    const { error: comandaError } = await this.supabase
      .from('comande')
      .update({ 
        status, 
        updated_at: new Date().toISOString() 
      })
      .eq('id', comandaId)
      .eq('restaurant_id', restaurantId); // Aggiungi questo filtro

    if (comandaError) {
      console.error('❌ Errore aggiornamento comanda:', comandaError);
      return false;
    }

    // 2. Aggiorna SOLO i piatti di questa comanda specifica
    // Prima verifichiamo quali piatti appartengono a questa comanda
    const { data: comandaItems, error: fetchError } = await this.supabase
      .from('order_items')
      .select('id')
      .eq('order_id', comandaId)
      .eq('restaurant_id', restaurantId);

    if (fetchError) {
      console.error('❌ Errore recupero items comanda:', fetchError);
      return false;
    }

    if (comandaItems && comandaItems.length > 0) {
      const itemIds = comandaItems.map(item => item.id);
      
      const { error: itemsError } = await this.supabase
        .from('order_items')
        .update({ 
          status, 
          updated_at: new Date().toISOString() 
        })
        .in('id', itemIds)
        .eq('restaurant_id', restaurantId);

      if (itemsError) {
        console.error('❌ Errore aggiornamento items:', itemsError);
        return false;
      }

      console.log(`✅ Aggiornati ${comandaItems.length} piatti per comanda ${comandaId}`);
    }

    return true;
  } catch (error) {
    console.error('❌ Errore updateComandaStatus:', error);
    return false;
  }
}

  async updateAllItemsInComanda(comandaId: string, status: string): Promise<boolean> {
    try {
      const restaurantId = await this.authService.getCurrentRestaurantId();
      if (!restaurantId) return false;

      const { error } = await this.supabase
        .from('order_items')
        .update({ 
          status,
          updated_at: new Date().toISOString()
        })
        .eq('order_id', comandaId)
        .eq('restaurant_id', restaurantId);

      return !error;
    } catch (error) {
      console.error('❌ Errore updateAllItemsInComanda:', error);
      return false;
    }
  }

  private async syncComandaStatus(comandaId: string): Promise<void> {
  const restaurantId = await this.authService.getCurrentRestaurantId();
  
  // 1. Recupera tutti i piatti di quella comanda
  const { data: items, error } = await this.supabase
    .from('order_items')
    .select('status')
    .eq('order_id', comandaId)
    .eq('restaurant_id', restaurantId);

  if (error || !items || items.length === 0) return;

  // 2. Logica di decisione: se tutti i piatti hanno lo stesso stato, la comanda lo segue
  const firstStatus = items[0].status;
  const allSame = items.every(item => item.status === firstStatus);

  if (allSame) {
    await this.supabase
      .from('comande')
      .update({ status: firstStatus, updated_at: new Date().toISOString() })
      .eq('id', comandaId);
  } else {
    // Logica opzionale: se almeno uno è "preparing", la comanda diventa "preparing"
    const hasPreparing = items.some(item => item.status === 'preparing');
    if (hasPreparing) {
      await this.supabase
        .from('comande')
        .update({ status: 'preparing', updated_at: new Date().toISOString() })
        .eq('id', comandaId);
    }
  }
}
}